isDisabled:
{{
  (() => {
    const nrNaboruPoprawny =
      /^FEMA\.\d{2}\.\d{2}-IP\.01-\d{3}\/\d{2}$/.test(InputNrNaboru.text || "");

    const wymaganePolaUzupelnione =
      nrNaboruPoprawny &&
      !!SelectTypNaboru.selectedOptionValue &&
      !!SelectStatus.selectedOptionValue;

    if (!wymaganePolaUzupelnione) {
      return true;
    }

    if (appsmith.store.trybNaboru === "dodawanie") {
      return false;
    }

    return !appsmith.store.naborZmieniony;
  })()
}}

onClick:
{{
  appsmith.store.trybNaboru === "edycja"
    ? editNabory.run(() => {
        getNabory.run(() => {
          showAlert("Zmiany zostały zapisane", "success");
        });
      })
    : addNabory.run(() => {
        getNabory.run(() => {
          showAlert("Nowy nabór został dodany", "success");
        });
      })
}}
